func openAnalyticsStore() (*store.Store, error) {
	fmt.Fprintf(os.Stderr, "opening local database...\n")
	db, err := store.Open(defaultDBPath("slack-pp-cli"))
	if err != nil {
		return nil, fmt.Errorf("opening local database: %w\nRun 'slack-pp-cli sync' first.", err)
	}
	rows, err := db.Query(`SELECT COUNT(*) FROM messages`)
	if err != nil {
		db.Close()
		return nil, fmt.Errorf("checking local messages: %w", err)
	}
	defer rows.Close()
	count := 0
	if rows.Next() {
		_ = rows.Scan(&count)
	}
	if count == 0 {
		db.Close()
		return nil, fmt.Errorf("local message cache is empty. Run 'slack-pp-cli sync' first")
	}
	return db, nil
}

